// The Safe Command API wraps stdout in a JSON envelope.
// Extract and parse the inner daily-brief JSON.
const envelope = $input.item.json;
const raw = (envelope.stdout || '').trim();
if (!raw) {
  throw new Error('Empty stdout from /adwi-daily-brief-n8n');
}
const brief = JSON.parse(raw);
if (!brief.ok) {
  throw new Error('Daily brief returned ok=false: ' + JSON.stringify(brief.errors));
}
return {
  ok: brief.ok,
  generated_at: brief.generated_at,
  brief_text: brief.brief,
  gmail_summary: brief.gmail?.summary || '',
  gmail_unread: brief.gmail?.unread_count || 0,
  gmail_available: brief.gmail?.available || false,
  services: brief.services,
  saved_to: brief.saved_to,
  warnings: (brief.warnings || []).join('; ')
};
